import assert from 'node:assert/strict';
import { mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { pathToFileURL } from 'node:url';
import test from 'node:test';

const scriptUrl = pathToFileURL(join(import.meta.dirname, 'mobile-bridge.mjs')).href;

async function importBridge(name) {
  const root = join(tmpdir(), `moonshine-mobile-bridge-${process.pid}-${name}`);
  const guardHome = join(root, 'guard');
  const modelCache = join(root, 'models');
  mkdirSync(guardHome, { recursive: true });
  mkdirSync(modelCache, { recursive: true });

  process.env.MONSTER_GUARD_HOME = guardHome;
  process.env.MOONSHINE_MODEL_CACHE_DIR = modelCache;
  process.env.MOONSHINE_MODEL_CONFIG = join(root, 'mobile-model.json');
  process.env.MOONSHINE_SKYMESH_CONFIG = join(root, 'skymesh.json');
  process.env.MOONSHINE_SKYMESH_STATUS = join(root, 'skymesh-status.json');
  process.env.MOONSHINE_SKYMESH_DISABLED = '1';

  const bridge = await import(`${scriptUrl}?case=${name}-${Date.now()}`);
  return { bridge, root, guardHome, modelCache };
}

test('modelStatus defaults to Qwen and reports cached knot size', async () => {
  const { bridge, modelCache } = await importBridge('model-status');
  writeFileSync(join(modelCache, 'qwen2.5-0.5b-instruct.knot'), 'knot');

  const status = bridge.modelStatus();

  assert.equal(status.active_model_id, 'qwen2.5-0.5b-instruct-q4');
  const active = status.models.find((model) => model.active);
  assert.equal(active.id, 'qwen2.5-0.5b-instruct-q4');
  assert.equal(active.present, true);
  assert.equal(active.size_bytes, 4);
});

test('configureModel persists active model and URL override without starting skymesh when disabled', async () => {
  const { bridge, root } = await importBridge('configure-model');

  const snapshot = bridge.configureModel('qwen-coder-7b', ' https://models.example/qwen-coder.knot ');
  const status = bridge.modelStatus();
  const config = JSON.parse(readFileSync(join(root, 'mobile-model.json'), 'utf8'));

  assert.equal(snapshot.id, 'qwen-coder-7b');
  assert.equal(snapshot.url, 'https://models.example/qwen-coder.knot');
  assert.equal(status.active_model_id, 'qwen-coder-7b');
  assert.equal(config.activeModelId, 'qwen-coder-7b');
  assert.equal(config.urlOverrides['qwen-coder-7b'], 'https://models.example/qwen-coder.knot');
});

test('skymeshStatus defaults on and normalizes snake_case status files', async () => {
  const { bridge, root } = await importBridge('skymesh-status');
  delete process.env.MOONSHINE_SKYMESH_DISABLED;
  writeFileSync(
    join(root, 'skymesh-status.json'),
    JSON.stringify({
      node: 'moonshine-test',
      model: 'qwen2.5-0.5b-instruct-q4',
      last_cache_key: 'cache-key-1',
      filled_cache_keys: ['cache-key-1', 9, 'cache-key-2'],
      last_error: null,
      updated_at: '2026-06-13T00:00:00.000Z',
    })
  );

  const status = bridge.skymeshStatus();

  assert.equal(status.enabled, true);
  assert.equal(status.node, 'moonshine-test');
  assert.equal(status.last_cache_key, 'cache-key-1');
  assert.deepEqual(status.filled_cache_keys, ['cache-key-1', 'cache-key-2']);
  assert.equal(status.last_error, null);
});

test('configureSkymesh writes persistent off switch', async () => {
  const { bridge, root } = await importBridge('configure-skymesh');
  delete process.env.MOONSHINE_SKYMESH_DISABLED;

  const status = bridge.configureSkymesh(false);
  const config = JSON.parse(readFileSync(join(root, 'skymesh.json'), 'utf8'));

  assert.equal(status.enabled, false);
  assert.equal(config.enabled, false);
  assert.equal(bridge.readSkymeshConfig().enabled, false);
});
